function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const adj: [number, number][][] = Array.from({ length: n }, () => []);
    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
    }

    let maxScore = -1;

    // We'll use a priority queue (max-heap based on min edge cost in the path)
    // Each element is [current node, total cost, min edge cost]
    const heap: [number, number, number][] = [];
    heap.push([0, 0, Infinity]);

    while (heap.length > 0) {
        heap.sort((a, b) => b[2] - a[2]); // Sort to simulate max-heap (not efficient, but works)
        const [u, totalCost, currentMin] = heap.pop()!;

        if (u === n - 1) {
            if (totalCost <= k) {
                maxScore = Math.max(maxScore, currentMin);
            }
            continue;
        }

        for (const [v, cost] of adj[u]) {
            if (!online[v] && v !== n - 1) continue;
            const newTotal = totalCost + cost;
            if (newTotal > k) continue;
            const newMin = Math.min(currentMin, cost);
            heap.push([v, newTotal, newMin]);
        }
    }

    return maxScore === Infinity ? -1 : maxScore;
}
